import React from "react";

const InventoryTable = ({ data }) => {
  if (data.length === 0) {
    return <p>No results found</p>;
  }

  return (
    <table>
      <thead>
        <tr>
          <th>Product</th>
          <th>Category</th>
          <th>Price</th>
          <th>Supplier</th>
        </tr>
      </thead>

      <tbody>
        {data.map((item) => (
          <tr key={item.id}>
            <td>{item.product_name}</td>
            <td>{item.category}</td>
            <td>₹{item.price}</td>
            <td>{item.supplier_name}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
};

export default InventoryTable;
